import{_ as e,o as t,c as o,ag as n}from"./chunks/framework.D2Ob5GRY.js";const u=JSON.parse('{"title":"机器管理","description":"","frontmatter":{},"headers":[],"relativePath":"account/machine-management.md","filePath":"account/machine-management.md"}'),r={name:"account/machine-management.md"};function i(c,a,l,h,s,m){return t(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="机器管理" tabindex="-1">机器管理 <a class="header-anchor" href="#机器管理" aria-label="Permalink to &quot;机器管理&quot;">​</a></h1><blockquote><p>什么是机器绑定、查看与解绑、不同套餐的机器数限制。</p></blockquote><h2 id="什么是「机器绑定」" tabindex="-1">什么是「机器绑定」 <a class="header-anchor" href="#什么是「机器绑定」" aria-label="Permalink to &quot;什么是「机器绑定」&quot;">​</a></h2><p>使用授权码激活时，每台运行 LinScio AI 的机器会与授权码绑定；套餐限制可绑定的机器数量，超出后新机器无法激活，需解绑旧机器。</p><h2 id="在用户中心查看已绑定的机器列表" tabindex="-1">在用户中心查看已绑定的机器列表 <a class="header-anchor" href="#在用户中心查看已绑定的机器列表" aria-label="Permalink to &quot;在用户中心查看已绑定的机器列表&quot;">​</a></h2><p>登录门户 → 用户中心 → 若有「机器管理」或「已绑定机器」入口，可查看机器 ID 列表与最后心跳时间。</p><h2 id="解绑旧机器-迁移服务器时必做" tabindex="-1">解绑旧机器（迁移服务器时必做） <a class="header-anchor" href="#解绑旧机器-迁移服务器时必做" aria-label="Permalink to &quot;解绑旧机器（迁移服务器时必做）&quot;">​</a></h2><p>在用户中心找到对应机器，执行「解绑」；解绑后该机器下次启动将无法通过校验，可在新服务器上重新激活。</p><h2 id="不同套餐的机器数限制" tabindex="-1">不同套餐的机器数限制 <a class="header-anchor" href="#不同套餐的机器数限制" aria-label="Permalink to &quot;不同套餐的机器数限制&quot;">​</a></h2><p>个人版/团队版/机构版对应不同机器数上限，具体以购买套餐为准；达上限时错误提示为「已达机器绑定上限」，需解绑后再绑新机。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/account/token-mechanism.html">令牌机制说明</a></li><li><a href="/docs/troubleshooting/common-errors.html#启动时账号验证失败">常见错误与解决方法</a></li></ul>',12)])])}const p=e(r,[["render",i]]);export{u as __pageData,p as default};
